class Solution:
    def __init__(self, w: List[int]):
        self.prefix = []
        s = 0
        for x in w:
            s += x
            self.prefix.append(s)
        self.total = s
    def pickIndex(self) -> int:
        import random, bisect
        r = random.random() * self.total
        return bisect.bisect_left(self.prefix, r)

