class Solution {
    vector<int> pre;
    int total;
public:
    Solution(vector<int>& w) {
        for (int x : w) { total += x; pre.push_back(total); }
    }
    int pickIndex() {
        int r = rand() % total;
        return lower_bound(pre.begin(), pre.end(), r + 1) - pre.begin();
    }
};
